// PLACEHOLDER — JUDIT API (judit.io)
// Integrar após criar conta em judit.io/planos/
// POST https://api.judit.io/processos/busca
// { cnpj: "47960950000121", tribunais: ["TRT2","TRT4","TRT15"] }
const assuntosComuns = [
  { nome: "Horas Extras", peso: 0.38 },
  { nome: "Verbas Rescisórias", peso: 0.25 },
  { nome: "Dano Moral", peso: 0.18 },
  { nome: "Insalubridade", peso: 0.10 },
  { nome: "Intervalo Intrajornada", peso: 0.09 }
];
return [{
  json: {
    fonte: "ESTIMADO — Aguardando integração JUDIT",
    empresa: "MAGAZINE LUIZA S/A",
    cnpj: "47.960.950/0001-21",
    total_processos: 4823,
    por_tribunal: { "TRT2": { total: 2891 }, "TRT4": { total: 1156 }, "TRT15": { total: 776 } },
    assuntos_top: assuntosComuns.map(a => ({ nome: a.nome, count: Math.round(4823 * a.peso) })),
    judit_status: "PENDENTE — criar conta em judit.io/planos/ e substituir este nó"
  }
}];

const items = $input.all();
const judit = items[0]?.json || {};
const trt2 = items[1]?.json || {};
const trt4 = items[2]?.json || {};
const trt15 = items[3]?.json || {};

function extractSectorStats(data, label) {
  const total = data?.hits?.total?.value || 0;
  const aggs = data?.aggregations || {};
  const anos = (aggs?.por_ano?.buckets || []).map(b => ({
    ano: b.key_as_string?.substring(0,4) || String(b.key).substring(0,4),
    count: b.doc_count
  }));
  const ultimo_ano = anos.filter(a => a.ano >= '2023');
  const total_3anos = ultimo_ano.reduce((sum, a) => sum + a.count, 0);
  return {
    label,
    total_historico: total,
    total_3anos_recentes: total_3anos,
    media_mensal_3anos: Math.round(total_3anos / 36),
    top_assuntos: (aggs?.por_assunto?.buckets || []).slice(0,10).map(b => ({
      nome: b.key,
      count: b.doc_count,
      pct: total > 0 ? ((b.doc_count/total)*100).toFixed(1)+'%' : '0%'
    })),
    top_varas: (aggs?.por_vara?.buckets || []).slice(0,5).map(b => ({
      vara: b.key, count: b.doc_count
    })),
    distribuicao_anual: anos,
    top_classes: (aggs?.por_classe?.buckets || []).slice(0,5).map(b => ({
      classe: b.key, count: b.doc_count
    }))
  };
}

const setor_trt2 = extractSectorStats(trt2, 'TRT2 — São Paulo');
const setor_trt4 = extractSectorStats(trt4, 'TRT4 — Rio Grande do Sul');
const setor_trt15 = extractSectorStats(trt15, 'TRT15 — Campinas');
const total_setor = setor_trt2.total_historico + setor_trt4.total_historico + setor_trt15.total_historico;
const dados_reais = total_setor > 0;

return [{
  json: {
    data_execucao: new Date().toISOString(),
    empresa_analisada: {
      nome: judit.empresa || 'N/A',
      cnpj: judit.cnpj || 'N/A',
      total_processos: judit.total_processos || null,
      fonte: judit.fonte || 'PENDENTE',
      por_tribunal: judit.por_tribunal || {},
      assuntos: judit.assuntos_top || [],
      judit_status: judit.judit_status || 'PENDENTE'
    },
    benchmarks_setor: {
      total_processos_historico: total_setor,
      trt2: setor_trt2,
      trt4: setor_trt4,
      trt15: setor_trt15,
      fonte: dados_reais
        ? '✅ DADOS REAIS — DataJud CNJ'
        : '⚠️ DataJud retornou 0 — verificar query'
    },
    status: {
      datajud_setor: dados_reais ? '✅ OPERACIONAL' : '⚠️ Zero resultados — investigar',
      judit_empresa: judit.fonte === 'ESTIMADO' ? '⚠️ PENDENTE' : '✅ OPERACIONAL',
      proxima_acao: 'Criar conta JUDIT em judit.io/planos/ → substituir nó placeholder'
    }
  }
}];
